import{_ as t,M as o,p as d,q as s,R as a,t as e,N as r,a1 as c}from"./framework-5866ffd3.js";const h={},i=c('<h1 id="nvm" tabindex="-1"><a class="header-anchor" href="#nvm" aria-hidden="true">#</a> NVM</h1><h2 id="它是什么" tabindex="-1"><a class="header-anchor" href="#它是什么" aria-hidden="true">#</a> 它是什么？</h2><p>NVM（全称：node.js version management） 是一个 node 版本控制工具，用于切换不同的 Node 版本。</p><h2 id="为什么需要它" tabindex="-1"><a class="header-anchor" href="#为什么需要它" aria-hidden="true">#</a> 为什么需要它？</h2><p>举个例子，我们在开发 Vue2 项目时，或许使用的还是 Node v14.x 版本，而在开发 Vue3 时，官方已经明确给出了前提条件是需要 Node 16+ 版本，我们在开发 Vue3 项目与维护 Vue2项目之间通过不断卸载与安装指定 Node 版本是不可取的，所以我们需要 NVM 帮我们管理 Node 版本，方便我们切换不同的 Node 版本。</p><h2 id="如何使用它" tabindex="-1"><a class="header-anchor" href="#如何使用它" aria-hidden="true">#</a> 如何使用它？</h2>',6),l={href:"https://github.com/coreybutler/nvm-windows/releases",target:"_blank",rel:"noopener noreferrer"},_={href:"https://blog.csdn.net/m0_59910554/article/details/126308956",target:"_blank",rel:"noopener noreferrer"};function p(u,N){const n=o("ExternalLinkIcon");return d(),s("div",null,[i,a("p",null,[e("前往 "),a("a",l,[e("NVM 版本发行库"),r(n)]),e(" 下载安装。你可以参考博文 "),a("a",_,[e("NVM 安装步骤"),r(n)]),e(" 进行安装。")])])}const m=t(h,[["render",p],["__file","index.html.vue"]]);export{m as default};
